typedef pair<pair<int, int>, int> point;
char grid[1000][1000], aux;
int n, m, xi, yi, xf, yf, max_time = 0, min_time = INT32_MAX;
int move_row[DIRECTIONS] = {-1, 0, 1, 0}; // N W S E
int move_col[DIRECTIONS] = {0, -1, 0, 1}; 
int turns[MAX_DIM][MAX_DIM] = {{INT32_MAX}}, distances[8][8];
int result = 0;

int oposite(int direction) {
    if (direction == N) {
        return S;
    } else if (direction == S) {
        return N;
    } else if (direction == E) {
        return W;
    } else {
