    set<pair<int, point>> pq;
    turns[xi][yi] = 0;
    // ma uit unde e finish-ul
    for (int i = 0; i < DIRECTIONS; i++) {
        int new_row = xi + move_row[i];
        int new_col = yi + move_col[i];
        // verific sa nu ies din grid
        if (new_row < 0 || new_row >= n){
            continue;
        } else if (new_col < 0 || new_col >= m) {
            continue;
        }
        if (grid[new_row][new_col] == 'W') {
            continue;
        }
        turns[new_row][new_col] = 0;
        pq.insert({0, {{new_row, new_col}, i}});
    }

// in coada am {distanta, {{x, y}, directie}}
    while(!pq.empty()) {
        pair<int, point> aux = *pq.begin();
        // pair<int, point> aux = pq.top();
        pq.erase(aux);
        int direction = aux.second.second;
        point arrive = aux.second;
        // cout << "Am ajuns aici : (" << arrive.first.first <<", " << arrive.first.second << ")" << endl;
