        }
        int number_turns = aux.first;
        for (int i = 0; i < DIRECTIONS; i++) {
            if (i == oposite(direction)) {
                continue;
            }
            int new_row = arrive.first.first + move_row[i];
            int new_col = arrive.first.second + move_col[i];
            if (new_row < 0 || new_row >= n){
                continue;
            } else if (new_col < 0 || new_col >= m) {
                continue;
            }

            // daca vecinul e deja vizitat sau e spatiu blocat
            if (grid[new_row][new_col] == 'W') {
                continue;
            }
            if (turns[new_row][new_col] < number_turns) {
                continue;
