import java.util.ArrayList;
import java.util.Collection;
import java.util.Collections;
import java.util.Comparator;

public class Valley {
    private ArrayList<Integer> peaks = new ArrayList<>();


    public void readInput() throws IOException {
        BufferedReader reader = new BufferedReader(new FileReader("valley.in"));
        String thing = reader.readLine();
        int temp = 0;
        int amount = Integer.parseInt(thing);
        while ((thing = reader.readLine()) != null) {
            for (int i = 0; i < thing.length(); i++) {
                if(thing.charAt(i) == ' '){
                    peaks.add(Integer.parseInt(thing, i - temp, i, 10));
                    temp = 0;
                } else if(peaks.size() == amount - 1) {
                    thing = thing.substring(i);
                    peaks.add(Integer.parseInt(thing, 10));
                } else {
                    temp++;
                }
            }
        }
    }

    public long solve() {
        long result = 0;
        int minIndex = 0;
        int minValueLeft = 0;
        int minValueRight = 0;
        for(int i = 0; i < peaks.size(); i++) {
            if(peaks.get(i) < peaks.get(minIndex)) {
                minIndex = i;
            }
        }


        minValueLeft = peaks.get(0);
        minValueRight = peaks.get(peaks.size() - 1);

        if(minIndex == 0) {
            minIndex++;
            result += (peaks.get(minIndex) - minValueLeft);
        }
        if(minIndex == peaks.size() - 1) {
            minIndex--;
            result += (peaks.get(minIndex) - minValueRight);
        }


        for(int i = 0; i < minIndex; i++) {
            if(minValueLeft < peaks.get(i)) {
                result += (peaks.get(i) - minValueLeft);
            } else if(minValueLeft > peaks.get(i)) {
                minValueLeft = peaks.get(i);
            }
        }

        for(int i = peaks.size() - 1; i > minIndex; i--) {
            if(minValueRight < peaks.get(i)) {
                result += (peaks.get(i) - minValueRight);
            } else if(minValueRight > peaks.get(i)) {
                minValueRight = peaks.get(i);
            }
        }

        return result;
    }

    public static void main(String[] args) throws IOException {
        Valley valley = new Valley();
        long result;
        valley.readInput();
        result = valley.solve();
        FileWriter fileWriter = new FileWriter("valley.out");
        fileWriter.write(String.valueOf(result) + '\n');
        System.out.println(result);
        fileWriter.close();
    }
}

