        import java.io.BufferedWriter;
import java.io.File;
import java.io.FileWriter;
import java.io.IOException;
import java.util.ArrayList;
import java.util.Collections;
import java.util.List;
import java.util.PriorityQueue;
import java.util.Scanner;

public class Fortificatii {
	public static int n, m, k, nrBarbari;
	@SuppressWarnings("unchecked")
	public static ArrayList<Pair> []adj = new ArrayList[1000000];
	public static ArrayList<Integer> locBarbari = new ArrayList<>();
	@SuppressWarnings("unchecked")
	public static ArrayList<Pair> []adjNoBarbarians = new ArrayList[1000000];

	public static class Pair implements Comparable<Pair> {
		public int destination;
		public long cost;

		Pair(int _destination, long _cost) {
			destination = _destination;
			cost = _cost;
		}

		public int compareTo(Pair rhs) {
			return Long.compare(cost, rhs.cost);
		}
	}

	public static class DijkstraResult {
		List<Long> d;
		List<Integer> p;

		DijkstraResult(List<Long> _d, List<Integer> _p) {
			d = _d;
			p = _p;
		}
	}

	public static DijkstraResult dijkstra(int source, int nodes, ArrayList<Pair> []adj) {
		List<Long> d = new ArrayList<>();
		List<Integer> p = new ArrayList<>();

		for (int node = 0; node <= nodes; node++) {
			d.add(Long.MAX_VALUE);
			p.add(0);
		}

		PriorityQueue<Pair> pq = new PriorityQueue<>();

		d.set(source, (long)0);
		pq.add(new Pair(source, 0));

		while (!pq.isEmpty()) {
			long cost = pq.peek().cost;
			int node = pq.poll().destination;

			if (cost > d.get(node)) {
				continue;
			}

			for (var e : adj[node]) {

				if (locBarbari.contains(e.destination)) {
					continue;
				}

				int neigh = e.destination;
				long w = e.cost;

				if (d.get(node) + w < d.get(neigh)) {
					d.set(neigh, d.get(node) + w);
					p.set(neigh, node);
					pq.add(new Pair(neigh, d.get(neigh)));
				}
			}
		}

		return new DijkstraResult(d, p);
	}

	public static void readInput() {
		try {
			File file;
			Scanner sc;
			file = new File("fortificatii.in");
			sc = new Scanner(file);
			n = sc.nextInt();
			m = sc.nextInt();
			k = sc.nextInt();
			nrBarbari = sc.nextInt();

			for (int i = 1; i <= nrBarbari; i++) {
				locBarbari.add(sc.nextInt());
			}
			for (int i = 1; i <= n; i++) {
				adj[i] = new ArrayList<>();
				adjNoBarbarians[i] = new ArrayList<>();
			}
			for (int i = 1; i <= m; i++) {
				int x, y, w;
				x = sc.nextInt();
				y = sc.nextInt();
				w = sc.nextInt();
				adj[x].add(new Pair(y, w));
				adj[y].add(new Pair(x, w));
			}

			sc.close();
		} catch (IOException e) {
			throw new RuntimeException(e);
		}
	}

	public static void balanceArray(ArrayList<Pair> arr) {
		for (int i = 1; i < arr.size(); i++) {
			if (arr.get(i).cost > arr.get(i - 1).cost) {
				arr.get(i - 1).cost++;
				return;
			}
			if (i == arr.size() - 1) {
				arr.get(i).cost++;
			}
		}
	}

	public static long minimumDistance(DijkstraResult dijkstraResult) {
		ArrayList<Pair> distanceToCities = new ArrayList<>();

		for (int i : locBarbari) {
			for (Pair neigh : adj[i]) {
				if (!locBarbari.contains(neigh.destination)
						&& dijkstraResult.d.get(neigh.destination) != Long.MAX_VALUE) {
					distanceToCities.add(neigh);
				}
			}
		}

		for (Pair i : distanceToCities) {
			i.cost += dijkstraResult.d.get(i.destination);
		}

		Collections.sort(distanceToCities);

		for (int i = 0; i < k; i++) {
			balanceArray(distanceToCities);
		}

		return distanceToCities.get(0).cost;
	}

	public static void main(String[] args) {
		readInput();
		DijkstraResult dijkstraResult = dijkstra(1, n, adj);

		long rez = minimumDistance(dijkstraResult);

		BufferedWriter writer;
		try {
			writer = new BufferedWriter(new FileWriter("fortificatii.out"));
			writer.write(rez + "\n");
			writer.close();
		} catch (IOException e) {
			e.printStackTrace();
		}
	}
}

