        import java.io.BufferedReader;
import java.io.File;
import java.io.FileReader;
import java.io.FileWriter;
import java.io.IOException;
import java.io.Reader;
import java.util.ArrayList;
import java.util.StringTokenizer;

class Graph1 {
	private int V;

	private ArrayList<Integer>[] adj;

	@SuppressWarnings("unchecked")
	Graph1(int v) {
		V = v;
		adj = new ArrayList[v];
		for (int i = 0; i < v; ++i) {
			adj[i] = new ArrayList<Integer>();

		}
	}

	void addEdge(int v, int w) {
		adj[v].add(w);
	}

	// kahn based toposort starting with context "context"
	int[] topologicalSort(int[] contextData, int startcontext) {
		int nr = 1;
		int[] result = new int[V + 1];
		int[] visited = new int[V + 1];
		int[] indegrees = getIndegrees();
		ArrayList<Integer> q = new ArrayList<Integer>();

		for (int i = 1; i < indegrees.length; i++) {
			// if it has the same context, prioritise adding it first
			if ((indegrees[i] == 0) && (contextData[i] == startcontext)) {
				q.add(0, i);
			} else if ((indegrees[i] == 0) && (contextData[i] != startcontext)) {
				// add the other context at the end
				q.add(i);
			}
			visited[i] = 0;
		}

		while (!q.isEmpty()) {
			int node = q.get(0);
			q.remove(0);
			result[nr] = node;
			nr++;
			visited[node] = 1;

			for (int neighbor : adj[node]) {
				if ((visited[neighbor] == 0) && (contextData[node] == contextData[neighbor])) {
					indegrees[neighbor]--;
					if (indegrees[neighbor] == 0) {
						q.add(0, neighbor);
					}
				} else if ((visited[neighbor] == 0) 
					&& (contextData[node] != contextData[neighbor])) {
					indegrees[neighbor]--;
					if (indegrees[neighbor] == 0) {
						q.add(neighbor);
					}
				}
			}
		}

		return result;
	}

	int[] getIndegrees() {
		int[] indegrees = new int[V];
		for (int i = 0; i < V; i++) {
			for (int v : adj[i]) {
				indegrees[v]++;
			}
		}
		indegrees[0] = 999999;
		return indegrees;
	}
}

public class Supercomputer {
	private static class MyScanner {
		private BufferedReader br;
		private StringTokenizer st;

		public MyScanner(Reader reader) {
			br = new BufferedReader(reader);
		}

		public String next() {
			while (st == null || !st.hasMoreElements()) {
				try {
					st = new StringTokenizer(br.readLine());
				} catch (IOException e) {
					e.printStackTrace();
				}
			}
			return st.nextToken();
		}

		public int nextInt() {
			return Integer.parseInt(next());
		}
	}

	public static void main(String[] args) {
		try {
			FileReader inputFile = new FileReader("supercomputer.in");
			MyScanner scanner = new MyScanner(inputFile);

			int N = scanner.nextInt();
			int M = scanner.nextInt();

			int[] contextData = new int[N + 1];
			for (int i = 1; i <= N; i++) {
				contextData[i] = scanner.nextInt();
			}

			int switchesCount1 = 0;
			int switchesCount2 = 0;
			int minSwitchesCount = 0;

			// create graph
			Graph1 graph = new Graph1(N + 1);
			for (int i = 0; i < M; i++) {
				graph.addEdge(scanner.nextInt(), scanner.nextInt());
			}

			// the ordering when we start with context 1
			int[] v = graph.topologicalSort(contextData, 1);
			for (int j = 1; j <= N - 1; j++) {
				if (contextData[v[j]] != contextData[v[j + 1]]) {
					switchesCount1++;
				}
			}

			// the ordering when we start with context 2
			v = graph.topologicalSort(contextData, 2);
			for (int j = 1; j <= N - 1; j++) {
				if (contextData[v[j]] != contextData[v[j + 1]]) {
					switchesCount2++;
				}
			}

			// find the minimum number of switches
			if (switchesCount1 < switchesCount2) {
				minSwitchesCount = switchesCount1;
			} else {
				minSwitchesCount = switchesCount2;
			}

			// write the result
			File outputFile = new File("supercomputer.out");
			FileWriter writer = new FileWriter(outputFile);
			writer.write(Integer.toString(minSwitchesCount));
			writer.close();
		} catch (IOException e) {
			e.printStackTrace();
		}
	}
}

