public class Teleportare {
	static class Edge {
		int destination;
		int time;

		public Edge(int destination, int time) {
			this.destination = destination;
			this.time = time;
		}
	}

	static class Teleport {
		int destination;
		int period;

		public Teleport(int destination, int period) {
			this.destination = destination;
			this.period = period;
		}
	}

	public static void main(String[] args) throws IOException {
		BufferedReader br = new BufferedReader(new FileReader("teleportare.in"));


		String[] params = br.readLine().split(" ");
		int N = Integer.parseInt(params[0]);

		List<Edge>[] graph = new ArrayList[N + 1];
		for (int i = 1; i <= N; i++) {
			graph[i] = new ArrayList<>();
		}

		int M = Integer.parseInt(params[1]);
		for (int i = 0; i < M; i++) {
			String[] edgeParams = br.readLine().split(" ");
			int X = Integer.parseInt(edgeParams[0]);
			int Y = Integer.parseInt(edgeParams[1]);
			int T = Integer.parseInt(edgeParams[2]);
			graph[X].add(new Edge(Y, T));
			graph[Y].add(new Edge(X, T));
		}

		List<Teleport>[] teleportation = new ArrayList[N + 1];
		for (int i = 1; i <= N; i++) {
			teleportation[i] = new ArrayList<>();
		}

		int K = Integer.parseInt(params[2]);
		for (int i = 0; i < K; i++) {
			String[] teleportParams = br.readLine().split(" ");
			int X = Integer.parseInt(teleportParams[0]);
			int Y = Integer.parseInt(teleportParams[1]);
			int P = Integer.parseInt(teleportParams[2]);
			teleportation[X].add(new Teleport(Y, P));
			teleportation[Y].add(new Teleport(X, P));
		}

		int[] dist = new int[N + 1];
		Arrays.fill(dist, Integer.MAX_VALUE);
		dist[1] = 0;

		PriorityQueue<int[]> pq = new PriorityQueue<>(Comparator.comparingInt(arr -> arr[1]));
		pq.offer(new int[] { 1, 0 });

		while (!pq.isEmpty()) {
			int[] curr = pq.poll();
			int node = curr[0];
			int time = curr[1];

			for (Edge edge : graph[node]) {
				int nextNode = edge.destination;
				int nextTime = time + edge.time;

				if (nextTime < dist[nextNode]) {
					dist[nextNode] = nextTime;
					pq.offer(new int[] { nextNode, nextTime });
				}
