					if (nextTime < dist[nextNode]) {
						dist[nextNode] = nextTime;
						pq.offer(new int[] { nextNode, nextTime });
					}
				}
			}
		}

		PrintWriter pw = new PrintWriter(new FileWriter("teleportare.out"));
		pw.println(dist[N]);
		pw.close();
		br.close();
	}
}

