			String[] lineSplit1 = line.split(" ");
			Integer currentValue = Integer.parseInt(lineSplit1[0]);
			Integer maxValue = Integer.parseInt(lineSplit1[2]);
			Integer minValue = Integer.parseInt(lineSplit1[1]);
			Actiune actiune = new Actiune(currentValue, maxValue, minValue);
			actiuni.add(actiune);
		}
		Integer[][][] dp = new Integer[N + 1][B + 1][L + 1];
		//initializam matricea
		for (int i = 0; i <= N; i++) {
			for (int j = 0; j <= B; j++) {
				for (int k = 0; k <= L; k++) {
					dp[i][j][k] = 0;
				}
			}
		}
		//caz general
		for (int i = 1; i <= N; i++) {
			for (int j = 1; j <= B; j++) {
				for (int k = 1; k <= L; k++) {
					int max_loss = actiuni.get(i).getCurrentValue()
							- actiuni.get(i).getMinValue();
					int current_price = actiuni.get(i).getCurrentValue();
					int max_profit = actiuni.get(i).getMaxValue()
							- actiuni.get(i).getCurrentValue();

					dp[i][j][k] = max(dp[i - 1][j][k], max(dp[i][j - 1][k], dp[i][j][k - 1]));

					if (current_price <= j && max_loss <= k) {
						dp[i][j][k] = max(dp[i][j][k], dp[i - 1][j - current_price]
								[k - max_loss] + max_profit);
					}
				}
			}
		}
		FileWriter fileWriter = new FileWriter("stocks.out");
		fileWriter.write(String.valueOf(dp[N][B][L]));
		fileWriter.close();

	}

}

