        import java.io.BufferedReader;
import java.io.FileReader;
import java.io.IOException;
import java.io.PrintStream;
import java.io.Reader;
import java.util.ArrayList;
import java.util.Arrays;
import java.util.StringTokenizer;


public class Magazin {

	private static int pos;

	private static int[] nodesOrder;

	private static int[] dfsOrder;

	public static void main(final String[] args) throws IOException {
		var scanner = new MyScanner(new FileReader("magazin.in"));

		int n = scanner.nextInt();
		int q = scanner.nextInt();

		// vector in care stocam nodurile in ordinea data de dfs
		dfsOrder = new int[n];

		// vector in care retinem pozitiile in care apar nodurile in dfs
		nodesOrder = new int[n + 1];

		// vector in care stocam numarul maxim de noduri
		// care mai pot fi vizitate dintr-un nod dat
		// pentru a afisa "-1" la nevoie
		int[] paths = new int[n + 1];


		// citim datele grafului
		ArrayList<ArrayList<Integer>> adj = new ArrayList<>();

		for (int i = 0; i < n; i++) {
			adj.add(new ArrayList<>());
		}

		for (int i = 2; i <= n; i++) {
			int x = scanner.nextInt();

			adj.get(x - 1).add(i);
		}


		// efectuam dfs
		dfs(adj,  1, paths);



		// calculam livrarile
		try (var printer = new PrintStream("magazin.out")) {

			for (int i = 1; i <= q; i++) {
				int source = scanner.nextInt();
				int expNumber = scanner.nextInt();

				// daca nu mai putem face "expNumber" expedieri din nodul dat
				// afisam "-1"
				if (expNumber > paths[source]) {
					printer.println("-1");
				} else {
					// altfel afisam nodul unde se va ajunge
					printer.println(dfsOrder[nodesOrder[source] + expNumber]);
				}
			}
		}
	}


	// algoritmul de dfs
	public static void dfs(ArrayList<ArrayList<Integer>> adj, int node, int[] paths) {


		// retinem pozitia nodului in dfs
		nodesOrder[node] = pos;
		// adaugam nodul in vectorul unde stocam rezultatul dfs-ului
		dfsOrder[pos] = node;
		pos++;

		for (int i = 0; i < adj.get(node - 1).size(); i++) {

			int neigh = adj.get(node - 1).get(i);
			// nodul nu a mai fost vizitat
			if (nodesOrder[neigh] == 0) {
				dfs(adj, neigh, paths);
				paths[node] += 1 + paths[neigh];
			}
		}

	}



	/**
	 * A class for buffering read operations, inspired from here:
	 * https://pastebin.com/XGUjEyMN.
	 */
	private static class MyScanner {
		private BufferedReader br;
		private StringTokenizer st;

		public MyScanner(Reader reader) {
			br = new BufferedReader(reader);
		}

		public String next() {
			while (st == null || !st.hasMoreElements()) {
				try {
					st = new StringTokenizer(br.readLine());
				} catch (IOException e) {
					e.printStackTrace();
				}
			}
			return st.nextToken();
		}

		public int nextInt() {
			return Integer.parseInt(next());
		}

		public long nextLong() {
			return Long.parseLong(next());
		}

		public double nextDouble() {
			return Double.parseDouble(next());
		}

		public String nextLine() {
			String str = "";
			try {
				str = br.readLine();
			} catch (IOException e) {
				e.printStackTrace();
			}
			return str;
		}
	}
}

