            } else {
                if ( (a[cord.first - 1][cord.second].second > a[cord.first][cord.second].second + 1 && 
                    (cord.first - 1 != x || cord.second != y)) || a[cord.first - 1][cord.second].second == -1) {
                    a[cord.first - 1][cord.second].second = a[cord.first][cord.second].second + 1;
                    q.push(make_pair(cord.first - 1, cord.second));
                }
            }
            if (cord.first + 1 >= n) { //sud
                if (a[cord.first][cord.second].second < *minim)
                    *minim = a[cord.first][cord.second].second;
            } else {
                if ( (a[cord.first + 1][cord.second].second > a[cord.first][cord.second].second + 1 && 
                    (cord.first + 1 != x || cord.second != y)) || a[cord.first + 1][cord.second].second == -1) {
                    a[cord.first + 1][cord.second].second = a[cord.first][cord.second].second + 1;
                    q.push(make_pair(cord.first + 1, cord.second));
                }
            }
        }
        if (a[cord.first][cord.second].first == 2 || a[cord.first][cord.second].first == 3) { //orizontal
            if (cord.second - 1 < 0) { //vest
                if (a[cord.first][cord.second].second < *minim)
                    *minim = a[cord.first][cord.second].second;
            } else {
                if ( (a[cord.first][cord.second - 1].second > a[cord.first][cord.second].second + 1 &&
                    (cord.first != x || cord.second - 1 != y)) || a[cord.first][cord.second - 1].second == -1) {
                    a[cord.first][cord.second - 1].second = a[cord.first][cord.second].second + 1;
                    q.push(make_pair(cord.first, cord.second -1));
                }
            }
            if (cord.second + 1 >= m) { //est
                if (a[cord.first][cord.second].second < *minim)
                    *minim = a[cord.first][cord.second].second;
            } else {
                if ( (a[cord.first][cord.second + 1].second > a[cord.first][cord.second].second + 1 &&
                    (cord.first != x || cord.second + 1 != y)) || a[cord.first][cord.second + 1].second == -1) {
