        #include<iostream>
#include<fstream>
#include <queue>
#include <map>
#include <cstring>
#include<string>
#include <list>
#include<algorithm>
#include <vector>
#include <set>
#define MAX 2147483647

int max_count = 0;
std::vector <int> final_solution;

// calculeaza numarul minim de numere necesare pentru a crea valoarea x
int numbers_needed(std::vector<int> solution, int x, std::vector<int> domain) {
    std::vector<int> dp;
    dp.push_back(0);
    for (int i = 1; i <= x; i++) {
        dp.push_back(MAX);
    }

    for (int i = 1; i <= x; i++) {
       for (int j = 0; j < solution.size(); j++) {
           if (i - domain[solution[j]] <  0) {
               break;
           }
            dp[i] = std::min(dp[i], dp[i - domain[solution[j]]] + 1);
       }
    }

    return dp[x];
}


void check(std::vector<int> &solution, std::vector<int> &domain, int T) {
    int c1 = 0;
    int c2 = 0;
    int i = 1;
    // verifica fiecare numar daca se poate crea din maxim T piese
    while (i <= domain.back() * T) {
        if (numbers_needed(solution, i, domain) <= T) {
            // numarul de valori consecutive
            c1++;
        } else {
            // se muta valoarea in c2 pentru a continua cautarea
            // numarului maxim de valori consecutive in c1
            if (c2 < c1) {
                c2 = c1;
            }
            // daca numarul de valori consecurive e deja maximul intalnit
            if (domain.back() * T < 2 * c2) {
                break;
            }
            c1 = 0;
        }
        i++;
    }
    if (c1 != 0) {
        c2 = c1;
    }
    // se salveaza numarul maxim intalnit pana in acest moment si
    // solutia cu numerele folosite
    if (max_count < c2) {
        max_count = c2;
        final_solution.clear();
        final_solution = solution;
    }
}

void back(int step, int stop, std::vector<int> &domain,
        std::vector<int> &solution, int T) {
    if (step == stop) {
        check(solution, domain, T);
        return;
    }

    unsigned i = step > 1 ? solution[step - 1] + 1 : 1;
    for (; i < domain.size(); ++i) {
        solution[step] = i;
        back(step + 1, stop, domain, solution, T);
    }
}


int main() {
    std::ifstream in;
    std::ofstream out;

    in.open("lego.in");
    out.open("lego.out");

    int K, N, T;

    // K = dimensiunea maxima a unei piese
    // N = numarul de piese selectate
    // T = numarul maxim de piese folosite
    in >> K >> N >> T;

    std::vector<int> domain(K), solution(N);

    // initializarea domeniului cu valori de la 1 la K
    for (int i = 0; i < K; ++i) {
        domain[i] = i + 1;
    }
    // primul numar ales este mereu 1
    solution[0] = 0;
    // step pleaca de la 1 deoarece am adaugat deja un element in solutie
    back(1, N, domain, solution, T);

    // numarul maxim de valori consecutive pe care le putem crea
    out << max_count << "\n";
    // numerele alese pentru a crea valorile consecutive
    for (int i = 0; i < final_solution.size(); i++) {
        out << domain[final_solution[i]] << " ";
    }
    out << "\n";
    return 0;
}


