        #include <bits/stdc++.h>
using namespace std;

vector<long long> dijkstra(int src, vector<vector<pair<long long,
 long long>>>& graph, long long n) {
    // parent and distance arrays
    vector<long long> parents(n, INT_MIN);
    vector<long long> dist(n, LONG_LONG_MAX);
    dist[src] = 0;

    // priority queue
    priority_queue<pair<long long, long long>,
    vector<pair<long long, long long>>, greater<pair<long long, long long>>> pq;
    pq.push(pair(src, dist[src]));

    // relaxation loop using nodes from queue
    while (!pq.empty()) {
        // popping node with shortest distance
        long long crnt_node = pq.top().first;
        pq.pop();

        // iterating through neighbours
        for (auto neighbour : graph[crnt_node]) {
            long long new_dist = dist[crnt_node] + neighbour.second;
            if (new_dist < dist[neighbour.first]) {
                dist[neighbour.first] = new_dist;
                parents[neighbour.first] = crnt_node;
                pq.push(pair(neighbour.first, new_dist));
            }
        }
    }

    return dist;
}

int main() {
    // reading graph data from file
    ifstream infile("drumuri.in");
    long long n, m, i;
    infile >> n >> m;
    vector<vector<pair<long long, long long>>> graph(n), reverse_graph(n);

    // reverse graph will contain edges in opposite direction
    for (i = 0; i < m; i++) {
        long long src, dest, cost;
        infile >> src >> dest >> cost;
        src--;
        dest--;
        graph[src].push_back(pair(dest, cost));
        reverse_graph[dest].push_back(pair(src, cost));
    }

    // the 3 relevant nodes
    long long x, y, z;
    infile >> x >> y >> z;
    x--;
    y--;
    z--;
    infile.close();

    // applying Dijkstra for x and y on graph and for z on reverse graph
    vector<long long> dist_x, dist_y, dist_z;
    dist_x = dijkstra(x, graph, n);
    dist_y = dijkstra(y, graph, n);
    dist_z = dijkstra(z, reverse_graph, n);

     // calculating minimum cost path
    long long min_cost = LONG_LONG_MAX;
    for (i = 0; i < n; i++) {
        if (dist_x[i] != LONG_LONG_MAX && dist_y[i]
        != LONG_LONG_MAX && dist_z[i] != LONG_LONG_MAX) {
            long long cost = dist_x[i] + dist_y[i] + dist_z[i];
            min_cost = min(min_cost, cost);
        }
    }

    // printing result to file
    ofstream outfile("drumuri.out");
    outfile << min_cost;
    outfile.close();
    return 0;
}

