		return (val1 > val2) ? (val1 + (val2 * 0.5)) : ((val1 * 0.5) + val2);
	}

	private static double three_products_sum(int val1, int val2, int val3) {
		int min = Math.min(val1, Math.min(val2, val3));

		if (min == val1) {
			return val2 + val3;
