        #include <iostream>
#include <fstream>
#include <vector>
#include <algorithm>
#include <set>

class Curse {
	public:
		void solve() {
			read();
			divideEtImpera(1, 1, a + 1);
			solve_dfs();
		}

	private:
	int n, m, a;
	std::vector<std::set<int>> edges;
	std::vector<std::vector<int>> matrix;

	void read() {
		// citim datele din fisier
		std::ifstream fin("curse.in");
		fin >> n >> m >> a;
		// alocam memorie
		matrix = std::vector<std::vector<int>> (a + 1,
									std::vector<int>((n + 1), 0));
		edges = std::vector<std::set<int>> (m + 1);

		for(int i = 1; i <= a; i++) {
			for(int j = 1; j <= n; j++) {
				fin >> matrix[i][j];
			}
		}
		fin.close();
	}

	void dfs(int node, std::vector<int>& used, std::vector<int>& topsort) {
		// functie dfs recursiva
		used[node] = 1;
		// parcurgem vecinii si verificam daca au fost vizitati
		for(auto neigh : edges[node]) {
			if(!used[neigh]) {
				dfs(neigh, used, topsort);
			}
		}
		// adaugam nodul in vector
		topsort.push_back(node);
	}

	void solve_dfs() {
		std::vector<int> topsort;
		std::vector<int> used(m + 1, 0);
		// parcurgem toate nodurile
		for(int node = 1; node <= m; node++) {
			if(!used[node]) {
				dfs(node, used, topsort);
			}
		}
		// afisam vectorul final
		std::ofstream fout("curse.out");
		for(int i = topsort.size() - 1; i >= 0; i--) {
			fout << topsort[i] << ' ';
		}
		fout << std::endl;
		fout.close();
	}

	void divideEtImpera(int nextTrack, int line1, int line2) {
		// daca am iesit din matrice sau aveam o matrice linie ne oprim
		if(nextTrack > n || line2 - line1 < 2) {
			return;
		}

		int newLine;
		// parcurgem pe coloana pana gasim 2 elemente distincte
		for(newLine = line1; newLine < line2; newLine++) {
			if(matrix[newLine][nextTrack] != matrix[line1][nextTrack]) {
				break;
			}
		}

		// adaugam muchia gasita
		if(newLine < line2) {
			edges[matrix[line1][nextTrack]].insert(matrix[newLine][nextTrack]);
		}

		// apelam recursiv pentru a cautata toate muchiile
		divideEtImpera(nextTrack + 1, line1, newLine);
		divideEtImpera(nextTrack, newLine, line2);
	}
};

int main() {
	auto * curse = new Curse();
	if(!curse) {
		std::cerr << "ERROR\n";
		return -1;
	}
	curse->solve();
	delete(curse);

	return 0;
}

