int task1(int n, int M, int x, vector <int>& p, vector <vector <int> >& g) {
	// suma maxima pe care o au la dispozitie pe a plati nota
	int sum = 0;
	sum = n * x;
	vector< vector<int> > dp(M + 1, vector<int>(sum + 1, 0));

	for(int m = 0; m <= M; m++) {
		dp[m][0] = 0;
	}

	for(int s = 0; s <= sum; s++) {
		dp[0][s] = 0;
	}

	for(int m = 1; m <= M; m++) {
		for(int s = 1; s <= sum; s++) {
			if (p[m - 1] > s) {
				// platou curent costa mai mult decat avem la dispozitie pentru
				// a plati
				dp[m][s] = dp[m - 1][s];
				continue;
			} else {
				// am pus -1 pt ca indicele la p si g incepe de la 0
				// verificam daca prin cumpararea platoului i suma notelor s-ar
				// maximiza
				if(dp[m - 1][s] > dp[m - 1][s - p[m - 1]] + get_grades(g, m - 1, n)) {
					dp[m][s] = dp[m - 1][s];
				} else {
					dp[m][s] = dp[m - 1][s - p[m - 1]] + get_grades(g, m - 1, n);
