        import java.io.BufferedReader;
import java.io.BufferedWriter;
import java.io.FileReader;
import java.io.FileWriter;
import java.io.IOException;
import java.lang.Exception;

public class Walsh {

	// (x, y) in dreptunghiul [ (tlx, tly), (drx, dry) ]
	private boolean in_rectangle(int x, int y, int tlx, int tly, int drx, int dry) {
		return (tlx <= x && x <= drx) && // x intre cele 2 laturi verticale
				(tly <= y && y <= dry); // y intre cele 2 laturi orizontale
	}

	// caut ce valoarea am pe (x, y), in patratul de dim D, colt stanga sus dat
	// in acest patrat a fost impratiat recursiv sirul: lower, lower + 1, ..., upper
	private int findVal(int x, int y, int tlx, int tly, int D, int lower, int upper) {
		if (D == 2) {
			if (x == tlx + 1 && y == tly + 1) {
				return 1;
			}
			return 0;
		}

		// dreapta jos
		int drx = tlx + D - 1;
		int dry = tly + D - 1;

		// celula din mijloc
		int mx = (tlx + drx) >> 1;
		int my = (tly + dry) >> 1;

		// caaut in care subdreptunghi se afla x, y
		// acesta are dimensiune de 2 ori mai mica => D / 2
		// fiecare sumbatrice are 1/4 din sirul de numere
		int new_D = (D >> 1);
		int cnt = (upper - lower + 1) >> 2;

		// caut in cadranul 1 (sus stanga)
		int new_lower = lower;
		int new_upper = new_lower + cnt - 1;

		if (in_rectangle(x, y, tlx, tly, mx, my)) {
			return findVal(x, y, tlx, tly, new_D, new_lower, new_upper);
		}

		// caut in cadranul 2 (sus dreapta)
		new_lower += cnt;
		new_upper += cnt;

		if (in_rectangle(x, y, tlx, my + 1, mx, dry)) {
			return findVal(x, y, tlx, my + 1, new_D, new_lower, new_upper);
		}

		// caut in cadranul 3 (jos stanga)
		new_lower += cnt;
		new_upper += cnt;

		if (in_rectangle(x, y, mx + 1, tly, drx, my)) {
			return findVal(x, y, mx + 1, tly, new_D, new_lower, new_upper);
		}

		// caut in cadranul 4 (jos dreapta)
		new_lower += cnt;
		new_upper += cnt;

		if (in_rectangle(x, y, mx + 1, my + 1, drx, dry)) {
			return (1 - findVal(x, y, mx + 1, my + 1, new_D, new_lower, new_upper));
		}

		// este mereu o solutie, nu se va ajunge aici
		return -1;
	}

	private int findSolution(int n, int x, int y) {
		int D = (1 << n);
		int lower = 1, upper = D * D;

		return findVal(x, y, 1, 1, D, lower, upper);
	}


	public static void main(String[] args) throws Exception {
		Walsh walsh = new Walsh();
		String path = "../walsh.in";

		BufferedReader bufferedReader = new BufferedReader(new FileReader(path));

		String line = bufferedReader.readLine();
		String[] tokens = line.split(" ");

		int n = Integer.parseInt(tokens[0]);
		int k = Integer.parseInt(tokens[1]);

		// calculez logaritm in baza 2 din numarul n
		int log = (int) (Math.log(n) / Math.log(2));


		BufferedWriter bufferedWriter;
		try {
			bufferedWriter = new BufferedWriter(new FileWriter("../walsh.out"));

			for (int i = 0; i < k; i++) {

				// citesc fiecare set de 2 numere de pe o linie ca un string
				line = bufferedReader.readLine();
				if (line == null) {
					break;
				}

				String[] tmp = line.split(" ");

				int x = Integer.parseInt(tmp[0]);
				int y = Integer.parseInt(tmp[1]);

				bufferedWriter.write((walsh.findSolution(log, x, y)) + "\n");
			}

			bufferedWriter.close();
		} catch (IOException e) {
			e.printStackTrace();
		}

		bufferedReader.close();
	}
}

