#include <iostream>
#include <algorithm>
#include <climits>

using namespace std;

int64_t SolveTask(int64_t cars_number, int64_t feribots, const vector<int>& a) {
    int64_t left = 0;
    int64_t right = 9223372036854775807;
    while (left < right) {
        int64_t mid = (left + right) / 2;
        int64_t used = 0;
        int64_t cur_weight = 0;
        bool ok = true;
        for (int i = 0; i < cars_number; i++) {
            if (a[i] > mid) {
                ok = false;
                break;
            }
            if (cur_weight + a[i] > mid) {
                used++;
                cur_weight = 0;
            }
            cur_weight += a[i];
        }
        used++;
        if (ok && used <= feribots) {
            right = mid;
        } else {
            left = mid + 1;
        }
    }
    int64_t res = left;

    return res;
}

vector<int> ReadVector(istream& is, int size) {
    vector<int> vec(size);
    for (auto& num : vec) {
        is >> num;
    }
    return vec;
}

int main() {
    ifstream fin("feribot.in");
    ofstream fout("feribot.out");

    int64_t cars_number, feribots;
    fin >> cars_number >> feribots;

    auto a = ReadVector(fin, cars_number);

    auto res = SolveTask(cars_number, feribots, a);
    fout << res << "\n";

    return 0;
}

