using namespace std;

// Verifică dacă puterea `power` poate fi atinsă pentru un curent unic
bool canAchievePower(const vector<int>& P, const vector<int>& C, double power) {
    double lo = -numeric_limits<double>::infinity();
    double hi = numeric_limits<double>::infinity();

    for (int i = 0; i < C.size(); i++) {
        if (P[i] < power) {
            // Puterea necesară este mai mare decât capacitatea serverului, iese
            return false;
        }
        double minCurrent = C[i] - (P[i] - power);
        double maxCurrent = C[i] + (P[i] - power);
        lo = max(lo, minCurrent);
        hi = min(hi, maxCurrent);

        if (lo > hi) {
            // Nu există un curent valid care să satisfacă toate condițiile
            return false;
        }
    }
    return true;
}

int main() {
    ifstream fin("servere.in");
    ofstream fout("servere.out");

    int N;
    fin >> N;
    vector<int> P(N), C(N);

    for (int i = 0; i < N; i++) {
        fin >> P[i];
    }
    for (int i = 0; i < N; i++) {
        fin >> C[i];
    }

    double lo = 0, hi = *min_element(P.begin(), P.end()), bestPower = 0;

    while (hi - lo > 1e-6) {
        double mid = (lo + hi) / 2;

        if (canAchievePower(P, C, mid)) {
            bestPower = mid;  // Actualizează cea mai bună putere posibilă
            lo = mid;
        } else {
            hi = mid;
        }
    }

    fout << fixed << setprecision(1) << bestPower << endl;
    fin.close();
    fout.close();

    return 0;
}

