        #include <iostream>
#include <fstream>
#include <cstdio>
#include <list>
#include <vector>
#include <stack>
#include <algorithm>

using namespace std;

int N, M, S;
void TarjanDFS(int node, vector<list<int>>& adj, vector<list<int>>& revadj,
                int* ts, vector<int>& found, vector<int>& low,
                vector<int>& stk, vector<int>& inStack,
                vector<int>& inWhichScc, int* sccCount, int* res) {
    found[node] = ++(*ts);
    low[node] = found[node];
    stk.push_back(node);
    inStack[node] = 1;

    for (auto& i : adj[node]) {
        if (inWhichScc[i] != 0) {
            if (inStack[i]) {
                low[node] = min(low[node], found[i]);
            }

            continue;
        }

        inWhichScc[i] = inWhichScc[node];
        TarjanDFS(i, adj, revadj, ts, found, low, stk, inStack,
                    inWhichScc, sccCount, res);

        low[node] = min(low[node], low[i]);
    }

    if (low[node] == found[node]) {
        // am gasit o noua componenta conexa
        vector<int> new_scc;
        (*sccCount) ++;

        int n;
        int foundS = 0;
        int comunica = 0;

        do {
            n = stk.back();
            if (n == S) {
                foundS = 1;
            }
            stk.pop_back();
            inStack[n] = 0;
            new_scc.push_back(n);
            inWhichScc[n] = (*sccCount);
        } while (n != node);

        if (!foundS) {
            // caut vecinii din graful reversed pentru fiecare nod din
            // componenta conexas
            for (auto n : new_scc) {
                for (auto& vecin : revadj[n]) {
                    if (inWhichScc[vecin] != inWhichScc[n]) {
                        // componenta conexa "comunica" cu o alta componenta
                        // conexa (cu un nod din alta SCC)
                        comunica = 1;
                        break;
                    }
                }

                if (comunica)
                    break;
            }

            if (!comunica && !foundS)
                (*res) ++;
        }
    }
}


int main() {
    // FILE* inputf = fopen
    // ("./public_tests/ferate/input/0-ferate.in", "r");  // debugg
    // FILE* outputf = fopen
    // ("./public_tests/ferate/out/0-ferate.out", "w");  // debugg
    FILE* inputf = fopen("ferate.in", "r");
    FILE* outputf = fopen("ferate.out", "w");

    if (inputf == NULL || outputf == NULL)
        return -1;

    int x, y;
    int sccCount = 0;
    int timestamp = 0;
    int res = 0;

    fscanf(inputf, "%d", &N);
    fscanf(inputf, "%d", &M);
    fscanf(inputf, "%d", &S);

    // vector cu liste de adiacenta
    vector<list<int>> adj(N + 1);
    // vector cu listele de adiacenta ale grafului cu muchiile inversate
    vector<list<int>> revadj(N + 1);
    // vector care retine in ce SCC se afla nodurile
    vector<int> inWhichScc(N + 1, 0);
    // vector care retine timestampul nodurilor
    vector<int> found(N + 1, 0);
    // vector care retine timestampul minim al nodurilor
    vector<int> low(N + 1, 0);
    // vector folosit ca stiva pentru alg Tarjan
    vector<int> stk;
    stk.reserve(N);
    // vector care retine daca nodurile sunt sau nu in prezent pe stiva
    vector<int> inStack(N + 1, 0);

    for (int i = 0; i < M; i ++) {
        x = y = 0;
        fscanf(inputf, "%d", &x);
        fscanf(inputf, "%d", &y);
        adj[x].push_back(y);
        revadj[y].push_back(x);
    }

    for (int i = 1; i <= N; i ++) {
        if (inWhichScc[i] == 0) {
            inWhichScc[i] = ++ sccCount;
            TarjanDFS(i, adj, revadj, &timestamp, found, low, stk, inStack,
            inWhichScc, &sccCount, &res);
        }
    }

    fprintf(outputf, "%d\n", res);

    fclose(inputf);
    fclose(outputf);
    return 0;
}

