        import java.io.File;
import java.util.Scanner;

public class Compresie {
	public static void main(String[] args) {
		new SolutionCompresie().solutionCompresie();
	}
}

class SolutionCompresie {
	int lenN;
	int[] a;
	int lenM;
	int[] b;

	void solutionCompresie() {

		//printez ambele siruri:
		readInput();

		int sumA = a[0];
		int sumB = b[0];
		int finalLen = 0;
		int aIndex = 0;
		int bIndex = 0;
		while (aIndex < lenN && bIndex < lenM) {
			System.out.println("sumA: " + sumA + " " + "sumB: " + sumB);
			if (sumA == sumB) {
				System.out.println("fin: " + finalLen);
				finalLen++;
				aIndex++;
				bIndex++;
				if (aIndex < lenN) {
					sumA = a[aIndex];
				}
				if (bIndex < lenM) {
					sumB = b[bIndex];
				}
			} else if (sumA < sumB) {
				aIndex++;
				if (aIndex < lenN) {
					sumA += a[aIndex];
				}
			} else {
				bIndex++;
				if (bIndex < lenM) {
					sumB += b[bIndex];
				}
			}
		}
		if (aIndex < lenN || bIndex < lenM) {
			for (aIndex = aIndex + 1; aIndex < lenN; aIndex++) {
				sumA += a[aIndex];
			}
			for (bIndex = bIndex + 1; bIndex < lenM; bIndex++) {
				sumB += b[bIndex];
			}
			if (sumA == sumB) {
				finalLen++;
			} else {
				finalLen = -1;
			}
		}
		System.out.println("fin: " + finalLen);
		writeToFile(finalLen);
	}

	public void readInput() {
		try {
			File file = new File("compresie.in");
			Scanner reader = new Scanner(file);
			this.lenN = reader.nextInt();
			this.a = new int[lenN];
			for (int i = 0; i < lenN; i++) {
				this.a[i] = reader.nextInt();
			}

			this.lenM = reader.nextInt();
			this.b = new int[lenM];
			for (int i = 0; i < lenM; i++) {
				this.b[i] = reader.nextInt();
			}

			reader.close();
		} catch (Exception e) {
			System.out.println("An error occurred.");
			e.printStackTrace();
		}
	}

	public void writeToFile(int result) {
		try {

			File file = new File("compresie.out");
			java.io.FileWriter writer = new java.io.FileWriter(file);

			writer.write(result + "\n");
			writer.close();
		} catch (Exception e) {
			System.out.println("An error occurred.");
			e.printStackTrace();
		}
	}
}
