		StringBuilder content = new StringBuilder();
		String line = reader.readLine();

		int nr = Integer.parseInt(line.split(" ")[0]);
		Prod[] calculatoare = new Prod[nr];

		final int buget1 = Integer.parseInt(line.split(" ")[1]);
		while ((line = reader.readLine()) != null) {
			Prod p = new Prod(Integer.parseInt(line.split(" ")[0]),
						Integer.parseInt(line.split(" ")[1]));
			calculatoare[j] = p;
			j++;
		}

		Arrays.sort(calculatoare, new Sortby());
		int min = calculatoare[0].productie;

		j = 0;
		int buget = buget1;
		while (buget > 0) {
			while (calculatoare[j].productie == min) {
				buget = buget - calculatoare[j].pret;
				if (buget < 0) {
					break;
				} else {
					calculatoare[j].productie++;
				}
				if (j < nr - 1) {
					j++;
				}
			}

			min = calculatoare[j].productie;
			if (j == nr - 1 && calculatoare[j - 1].productie < min) {
				min = calculatoare[j - 1].productie;
			}
			j = 0;
		}

		File myOut = new File("crypto.out");
		FileWriter myWriter = new FileWriter(myOut);
		myWriter.write("" + min);
		myWriter.close();
	}
}


